{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://github.com/aiphenomenon/inthebeginning/session_logs/transcript_schema.json",
  "title": "Session Transcript",
  "description": "JSON transcript companion file for session logs. Generated alongside session_logs/v{VERSION}-session.md at each conversation turn.",
  "type": "object",
  "required": ["session_id", "version", "started_at", "turns"],
  "properties": {
    "session_id": {
      "type": "string",
      "description": "Session identifier, e.g. 'v21'",
      "examples": ["v21"]
    },
    "version": {
      "type": "string",
      "description": "Version label, e.g. 'V21'",
      "examples": ["V21"]
    },
    "started_at": {
      "type": "string",
      "description": "Session start time in CT with UTC, format: 'YYYY-MM-DD HH:MM CT (HH:MM UTC)'",
      "pattern": "^\\d{4}-\\d{2}-\\d{2} \\d{2}:\\d{2} CT \\(\\d{2}:\\d{2} UTC\\)$",
      "examples": ["2026-03-08 14:30 CT (20:30 UTC)"]
    },
    "turns": {
      "type": "array",
      "description": "Array of conversation turn records",
      "items": {
        "$ref": "#/$defs/turn"
      }
    }
  },
  "$defs": {
    "turn": { ... },
    "user_input": { ... },
    "action": { ... }
  }
}

{
  "hooks": {
    "SessionStart": [
      {
        "matcher": "startup",
        "hooks": [
          {
            "type": "command",
            "command": "bash \"$CLAUDE_PROJECT_DIR/.claude/hooks/session-start.sh\""
          }
        ]
      }
    ],
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "bash \"$CLAUDE_PROJECT_DIR/.claude/hooks/pre-commit-plan-check.sh\""
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "Edit|Write",
        "hooks": [
          {
            "type": "command",
            "command": "bash \"$CLAUDE_PROJECT_DIR/.claude/hooks/lint-on-write.sh\""
          }
        ]
      },
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "bash \"$CLAUDE_PROJECT_DIR/.claude/hooks/post-bash-test-nudge.sh\""
          }
        ]
      }
    ],
    "Stop": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "bash \"$CLAUDE_PROJECT_DIR/.claude/hooks/stop-check.sh\""
          }
        ]
      }
    ]
  },
  "permissions": {
    "allow": [],
    "deny": []
  }
}

{
